// App.js - COMPLETE UPDATED VERSION
import React from "react";
import { BrowserRouter as Router, Routes, Route } from "react-router-dom";
import { CartProvider } from "./pages/CartContext";
import { AuthProvider } from "./components/AuthContext"; // Add AuthProvider
import Navbar from "./components/Navbar";
import HeroSection from "./components/HeroSection";
import Collection from "./components/Collection";
import About from "./components/About";
import Footer from "./components/Footer";
import SummerCollection from './components/SummerCollection';
import CasualCollection from "./components/CasualCollection";
import JewelryCollection from "./components/JewelryCollection";
import Login from "./components/Login"; // Add Login component
import Signup from "./components/Signup"; // Add Signup component
import Profile from "./components/Profile"; // Add Profile component
import ScrollToTop from "./components/ScrollToTop";
import "./App.css";

function App() {
  return (
    <AuthProvider> {/* Wrap with AuthProvider first */}
      <CartProvider> {/* Then wrap with CartProvider */}
        <Router>
          <ScrollToTop />
          <div className="app">
            <Navbar />
            <Routes>
              <Route
                path="/"
                element={
                  <>
                    <HeroSection />
                    <Collection />
                    <About />
                  </>
                }
              />
              <Route path="/collection" element={<Collection />} />
              <Route path="/about" element={<About />} />
              <Route path="/summer-collection" element={<SummerCollection />} />
              <Route path="/casual-collection" element={<CasualCollection />} />
              <Route path="/jewelry-collection" element={<JewelryCollection />} />
              {/* Add new auth routes */}
              <Route path="/login" element={<Login />} />
              <Route path="/signup" element={<Signup />} />
              <Route path="/profile" element={<Profile />} />
            </Routes>
            <Footer />
          </div>
        </Router>
      </CartProvider>
    </AuthProvider>
  );
}

export default App;
